18	// basic data structure
19	
20	// Limitation: cannot point to itself (zero is used to represent NULL pointer)
21	template <class T = char, class Offset = int32_t>
22	class OffsetPtr {
23	 public:
24	  OffsetPtr() = default;
25	  OffsetPtr(Offset offset) : offset_(offset) {}
26	  OffsetPtr(const T* ptr) : OffsetPtr(to_offset(ptr)) {}
27	  OffsetPtr(const OffsetPtr<T>& ptr) : OffsetPtr(ptr.get()) {}
28	  OffsetPtr<T>& operator=(const OffsetPtr<T>& ptr) {
29	    offset_ = to_offset(ptr.get());
30	    return *this;
31	  }
32	  OffsetPtr<T>& operator=(const T* ptr) {
33	    offset_ = to_offset(ptr);
34	    return *this;
35	  }
36	  operator bool() const { return !!offset_; }
37	  T* operator->() const { return get(); }
38	  T& operator*() const { return *get(); }
39	  T& operator[](size_t index) const { return *(get() + index); }
40	  T* get() const {
41	    if (!offset_)
42	      return NULL;
43	    return reinterpret_cast<T*>((char*)&offset_ + offset_);
44	  }
45	
46	 private:
47	  Offset to_offset(const T* ptr) const {
48	    return ptr ? (char*)ptr - (char*)(&offset_) : 0;
49	  }
50	  Offset offset_ = 0;
51	};
52	
53	struct String {
54	  OffsetPtr<char> data;
55	  const char* c_str() const { return data.get(); }
56	  size_t length() const { return c_str() ? strlen(c_str()) : 0; }
57	  bool empty() const { return !data || !data[0]; }
58	};
59	
60	template <class T, class Size = uint32_t>
61	struct Array {
62	  Size size;
63	  T at[1];
64	  T* begin() { return &at[0]; }
65	  T* end() { return &at[0] + size; }
66	  const T* begin() const { return &at[0]; }
67	  const T* end() const { return &at[0] + size; }
68	};
69	
70	template <class T, class Size = uint32_t>
71	struct List {
72	  Size size;
73	  OffsetPtr<T> at;
74	  T* begin() { return &at[0]; }
75	  T* end() { return &at[0] + size; }
76	  const T* begin() const { return &at[0]; }
77	  const T* end() const { return &at[0] + size; }
78	};
79	
80	// MappedFile class definition
81	
82	class MappedFileImpl;
83	
84	class RIME_DLL MappedFile {
85	 protected:
86	  explicit MappedFile(const path& file_path);
87	  virtual ~MappedFile();
88	
89	  bool Create(size_t capacity);
90	  bool OpenReadOnly();
91	  bool OpenReadWrite();
92	  bool Flush();
93	  bool Resize(size_t capacity);
94	  bool ShrinkToFit();
95	
96	  template <class T>
97	  T* Allocate(size_t count = 1);
98	
99	  template <class T>
100	  Array<T>* CreateArray(size_t array_size);
101	
102	  String* CreateString(const string& str);
103	  bool CopyString(const string& src, String* dest);
104	
105	  size_t capacity() const;
106	  char* address() const;
107	
108	 public:
109	  // noncpyable
110	  MappedFile(const MappedFile&) = delete;
111	  MappedFile& operator=(const MappedFile&) = delete;
112	
113	  bool Exists() const;
114	  bool IsOpen() const;
115	  void Close();
116	  bool Remove();
117	
118	  template <class T>
119	  T* Find(size_t offset);
120	
121	  const path& file_path() const { return file_path_; }
122	  size_t file_size() const { return size_; }
123	
124	 private:
125	  path file_path_;
126	  size_t size_ = 0;
127	  the<MappedFileImpl> file_;
128	};
129	
130	// member function definitions
131	
132	#define RIME_ALIGNED(size, T) ((size + alignof(T) - 1) & ~(alignof(T) - 1))
133	
134	template <class T>
135	T* MappedFile::Allocate(size_t count) {
136	  if (!IsOpen())
137	    return NULL;
138	
139	  size_t used_space = RIME_ALIGNED(size_, T);
140	  size_t required_space = sizeof(T) * count;
141	  size_t file_size = capacity();
142	  if (used_space + required_space > file_size) {
143	    // not enough space; grow the file
144	    size_t new_size = (std::max)(used_space + required_space, file_size * 2);
145	    if (!Resize(new_size) || !OpenReadWrite())
146	      return NULL;
147	  }
148	  T* ptr = reinterpret_cast<T*>(address() + used_space);
149	  std::memset((void*)ptr, 0, required_space);
150	  size_ = used_space + required_space;
151	  return ptr;
152	}
153	
154	template <class T>
155	T* MappedFile::Find(size_t offset) {
156	  if (!IsOpen() || offset > size_)
157	    return NULL;
158	  return reinterpret_cast<T*>(address() + offset);
159	}
160	
161	template <class T>
162	Array<T>* MappedFile::CreateArray(size_t array_size) {
163	  size_t num_bytes = sizeof(Array<T>) + sizeof(T) * (array_size - 1);
164	  Array<T>* ret = reinterpret_cast<Array<T>*>(Allocate<char>(num_bytes));
165	  if (!ret)
166	    return NULL;
167	  ret->size = array_size;
168	  return ret;
169	}
