3	// Distributed under the BSD License
4	//
5	// 2011-11-27 GONG Chen <chen.sst@gmail.com>
6	//
7	#include <filesystem>
8	#include <cfloat>
9	#include <cmath>
10	#include <fstream>
11	#include <rime/algo/algebra.h>
12	#include <rime/algo/utilities.h>
13	#include <rime/dict/corrector.h>
14	#include <rime/dict/dict_compiler.h>
15	#include <rime/dict/dict_settings.h>
16	#include <rime/dict/dictionary.h>
17	#include <rime/dict/entry_collector.h>
18	#include <rime/dict/preset_vocabulary.h>
19	#include <rime/dict/prism.h>
20	#include <rime/dict/reverse_lookup_dictionary.h>
21	#include <rime/dict/table.h>
22	#include <rime/resource.h>
23	#include <rime/service.h>
24	
25	namespace rime {
26	
27	DictCompiler::DictCompiler(Dictionary* dictionary)
28	    : dict_name_(dictionary->name()),
29	      packs_(dictionary->packs()),
30	      prism_(dictionary->prism()),
31	      tables_(dictionary->tables()),
32	      source_resolver_(
33	          Service::instance().CreateResourceResolver({"source_file", "", ""})),
34	      target_resolver_(Service::instance().CreateStagingResourceResolver(
35	          {"target_file", "", ""})) {}
36	
37	DictCompiler::~DictCompiler() {}
38	
39	static bool load_dict_settings_from_file(DictSettings* settings,
40	                                         const path& dict_file) {
41	  std::ifstream fin(dict_file.c_str());
42	  bool success = settings->LoadDictHeader(fin);
43	  fin.close();
44	  return success;
45	}
46	
47	static bool get_dict_files_from_settings(vector<path>* dict_files,
48	                                         DictSettings& settings,
49	                                         ResourceResolver* source_resolver) {
50	  if (auto tables = settings.GetTables()) {
51	    for (auto it = tables->begin(); it != tables->end(); ++it) {
52	      string dict_name = As<ConfigValue>(*it)->str();
53	      auto dict_file = source_resolver->ResolvePath(dict_name + ".dict.yaml");
54	      if (!std::filesystem::exists(dict_file)) {
55	        LOG(ERROR) << "source file '" << dict_file << "' does not exist.";
56	        return false;
57	      }
58	      dict_files->push_back(dict_file);
59	    }
60	  }
61	  return true;
62	}
63	
64	static uint32_t compute_dict_file_checksum(uint32_t initial_checksum,
65	                                           const vector<path>& dict_files,
66	                                           DictSettings& settings) {
67	  if (dict_files.empty()) {
68	    return initial_checksum;
69	  }
70	  ChecksumComputer cc(initial_checksum);
71	  for (const auto& file_path : dict_files) {
72	    cc.ProcessFile(file_path);
73	  }
74	  if (settings.use_preset_vocabulary()) {
75	    cc.ProcessFile(PresetVocabulary::DictFilePath(settings.vocabulary()));
76	  }
77	  return cc.Checksum();
78	}
79	
80	bool DictCompiler::Compile(const path& schema_file) {
81	  LOG(INFO) << "compiling dictionary for " << schema_file;
82	  bool build_table_from_source = true;
83	  DictSettings settings;
84	  auto dict_file = source_resolver_->ResolvePath(dict_name_ + ".dict.yaml");
85	  if (!std::filesystem::exists(dict_file)) {
86	    LOG(ERROR) << "source file '" << dict_file << "' does not exist.";
87	    build_table_from_source = false;
88	  } else if (!load_dict_settings_from_file(&settings, dict_file)) {
89	    LOG(ERROR) << "failed to load settings from '" << dict_file << "'.";
90	    return false;
91	  }
92	  vector<path> dict_files;
93	  if (!get_dict_files_from_settings(&dict_files, settings,
94	                                    source_resolver_.get())) {
95	    return false;
96	  }
97	  uint32_t dict_file_checksum =
98	      compute_dict_file_checksum(0, dict_files, settings);
99	  uint32_t schema_file_checksum =
100	      schema_file.empty() ? 0 : Checksum(schema_file);
101	  bool rebuild_table = false;
102	  bool rebuild_prism = false;
103	  const auto& primary_table = tables_[0];
104	  if (primary_table->Exists() && primary_table->Load()) {
105	    if (build_table_from_source) {
106	      rebuild_table = primary_table->dict_file_checksum() != dict_file_checksum;
107	    } else {
108	      dict_file_checksum = primary_table->dict_file_checksum();
109	      LOG(INFO) << "reuse existing table: " << primary_table->file_path();
110	    }
111	    primary_table->Close();
112	  } else if (build_table_from_source) {
113	    rebuild_table = true;
114	  } else {
115	    LOG(ERROR) << "neither " << dict_name_ << ".dict.yaml nor " << dict_name_
116	               << ".table.bin exists.";
117	    return false;
118	  }
119	  if (prism_->Exists() && prism_->Load()) {
120	    rebuild_prism = prism_->dict_file_checksum() != dict_file_checksum ||
121	                    prism_->schema_file_checksum() != schema_file_checksum;
122	    prism_->Close();
123	  } else {
124	    rebuild_prism = true;
125	  }
126	  LOG(INFO) << dict_file << "[" << dict_files.size() << " file(s)]"
127	            << " (" << dict_file_checksum << ")";
128	  LOG(INFO) << schema_file << " (" << schema_file_checksum << ")";
129	  {
130	    the<ResourceResolver> resolver(
131	        Service::instance().CreateDeployedResourceResolver(
132	            {"find_reverse_db", "", ".reverse.bin"}));
133	    ReverseDb reverse_db(resolver->ResolvePath(dict_name_));
134	    if (!reverse_db.Exists() || !reverse_db.Load() ||
135	        reverse_db.dict_file_checksum() != dict_file_checksum) {
136	      rebuild_table = true;
137	    }
138	  }
139	  if (build_table_from_source && (options_ & kRebuildTable)) {
140	    rebuild_table = true;
141	  }
142	  if (options_ & kRebuildPrism) {
143	    rebuild_prism = true;
144	  }
145	  Syllabary syllabary;
146	  if (rebuild_table) {
147	    EntryCollector collector;
148	    if (!BuildTable(0, collector, &settings, dict_files, dict_file_checksum)) {
149	      return false;
150	    }
151	    syllabary = std::move(collector.syllabary);
152	  } else if (packs_.size() > 0) {
153	    if (primary_table->Load() && primary_table->GetSyllabary(&syllabary))
154	      primary_table->Close();
155	    else
156	      LOG(WARNING) << "couldn't load syllabary from '" << schema_file << "'";
157	  }
158	  if (rebuild_prism &&
159	      !BuildPrism(schema_file, dict_file_checksum, schema_file_checksum)) {
160	    return false;
161	  }
162	  for (int table_index = 1; table_index < tables_.size(); ++table_index) {
163	    const auto& pack_name = packs_[table_index - 1];
164	    auto pack_table = tables_[table_index];
165	    EntryCollector collector(std::move(syllabary));
166	    DictSettings settings;
167	    auto dict_file = source_resolver_->ResolvePath(pack_name + ".dict.yaml");
168	    if (!std::filesystem::exists(dict_file)) {
169	      if (pack_table->Exists())
