172	                  << pack_table->file_path() << "'";
173	      else
174	        LOG(ERROR) << "neither pack source file '" << dict_file
175	                   << "' nor a prebuilt table exists";
176	      continue;
177	    }
178	    if (!load_dict_settings_from_file(&settings, dict_file)) {
179	      LOG(ERROR) << "failed to load settings from '" << dict_file << "'.";
180	      continue;
181	    }
