261	    vector<of<RawDictEntry>>().swap(collector.entries);
262	    if (settings->sort_order() != "original") {
263	      vocabulary.SortHomophones();
264	    }
265	    table->Remove();
266	    if (!table->Build(collector.syllabary, vocabulary, collector.num_entries,
267	                      dict_file_checksum) ||
268	        !table->Save()) {
269	      return false;
270	    }
271	  }
272	  // build reverse db for the primary table
273	  if (table_index == 0 &&
274	      !BuildReverseDb(settings, collector, vocabulary, dict_file_checksum)) {
275	    return false;
276	  }
277	  return true;
