15	bool DictSettings::LoadDictHeader(std::istream& stream) {
16	  if (!stream.good()) {
17	    LOG(ERROR) << "failed to load dict header from stream.";
18	    return false;
19	  }
20	  std::stringstream header;
21	  string line;
22	  while (getline(stream, line)) {
23	    boost::algorithm::trim_right(line);
24	    header << line << std::endl;
25	    if (line == "...") {  // yaml doc ending
26	      break;
27	    }
28	  }
29	  if (!LoadFromStream(header)) {
30	    return false;
31	  }
32	  if ((*this)["name"].IsNull() || (*this)["version"].IsNull()) {
33	    LOG(ERROR) << "incomplete dict header.";
34	    return false;
35	  }
36	  return true;
37	}
